scripts.copy:extensions:
node -e "
const fs=require('fs');
const p=require('path');
function c(s,d){
  if(fs.existsSync(d))fs.rmSync(d,{recursive:true,force:true});
  if(!fs.existsSync(d))fs.mkdirSync(d,{recursive:true});
  fs.readdirSync(s).forEach(f=>{
    const sp=p.join(s,f),dp=p.join(d,f);
    fs.statSync(sp).isDirectory()?c(sp,dp):fs.copyFileSync(sp,dp)
  })
}
// Copy defaults extensions

c('extensions/defaults/security-audit','dist/extensions/defaults/security-audit');
c('extensions/defaults/soul','dist/extensions/defaults/soul');
c('extensions/defaults/presence','dist/extensions/defaults/presence');
c('extensions/defaults/interview','dist/extensions/defaults/interview');
c('extensions/defaults/loop','dist/extensions/defaults/loop');
c('extensions/defaults/team','dist/extensions/defaults/team');
c('extensions/defaults/mcp','dist/extensions/defaults/mcp');
// Copy optional extensions
c('extensions/optional/simplify','dist/extensions/optional/simplify');
c('extensions/optional/export-html','dist/extensions/optional/export-html');
console.log('Extensions copied to dist/');
"
